const content = $json.body.content.trim();
const discordUser = $json.body.author.username;
const parts = content.split(/\s+/);
const cmd = parts[0].toLowerCase();

const now = new Date();
const fourWeeksAgo = new Date(now);
fourWeeksAgo.setDate(now.getDate() - 28);
const defaultDateFrom = fourWeeksAgo.toISOString().slice(0, 10);
const defaultDateTo = now.toISOString().slice(0, 10);

const fiftyTwoWeeksAgo = new Date(now);
fiftyTwoWeeksAgo.setDate(now.getDate() - 364);
const storesDateFrom = fiftyTwoWeeksAgo.toISOString().slice(0, 10);

function parseYYYYMMDD(s) {
  if (!s || !/^\d{8}$/.test(s)) return null;
  return `${s.slice(0,4)}-${s.slice(4,6)}-${s.slice(6,8)}`;
}

function formatDisplayDate(isoDate) {
  if (!isoDate) return '';
  const d = new Date(isoDate);
  return d.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
}

let result = { cmd, discordUser, valid: true, error: null };

if (cmd === '!help') {
  result.action = 'help';

} else if (cmd === '!email') {
  const email = parts[1] ?? null;
  if (!email || !/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) {
    result.valid = false;
    result.error = '❌ Invalid email address. Usage: !email you@example.com';
  } else {
    result.action = 'email';
    result.email = email;
  }

} else if (cmd === '!stores') {
  result.action = 'stores';
  result.dateFrom = storesDateFrom;
  result.dateTo = defaultDateTo;

} else if (cmd === '!last') {
  let n = parseInt(parts[1] ?? '1', 10);
  if (isNaN(n) || n < 1) {
    result.valid = false;
    result.error = '❌ Invalid number. Usage: !last N (e.g. !last 5)';
  } else if (n > 20) {
    result.valid = false;
    result.error = '❌ Maximum allowed is 20. Usage: !last N (e.g. !last 20)';
  } else {
    result.action = 'last';
    result.n = n;
  }

} else if (cmd === '!summary') {
  let dateFrom, dateTo;
  if (parts.length >= 3) {
    dateFrom = parseYYYYMMDD(parts[1]);
    dateTo = parseYYYYMMDD(parts[2]);
    if (!dateFrom || !dateTo) {
      result.valid = false;
      result.error = '❌ Invalid date format. Usage: !summary YYYYMMDD YYYYMMDD\nExample: !summary 20260501 20260524';
    } else if (dateFrom > dateTo) {
      result.valid = false;
      result.error = '❌ Start date must be before end date.';
    }
  } else {
    dateFrom = defaultDateFrom;
    dateTo = defaultDateTo;
  }
  if (result.valid) {
    result.action = 'summary';
    result.dateFrom = dateFrom;
    result.dateTo = dateTo;
    result.displayFrom = formatDisplayDate(dateFrom);
    result.displayTo = formatDisplayDate(dateTo);
  }

} else if (cmd === '!export') {
  let dateFrom, dateTo;
  if (parts.length >= 3) {
    dateFrom = parseYYYYMMDD(parts[1]);
    dateTo = parseYYYYMMDD(parts[2]);
    if (!dateFrom || !dateTo) {
      result.valid = false;
      result.error = '❌ Invalid date format. Usage: !export YYYYMMDD YYYYMMDD\nExample: !export 20260501 20260524';
    } else if (dateFrom > dateTo) {
      result.valid = false;
      result.error = '❌ Start date must be before end date.';
    }
  } else {
    dateFrom = defaultDateFrom;
    dateTo = defaultDateTo;
  }
  if (result.valid) {
    result.action = 'export';
    result.dateFrom = dateFrom;
    result.dateTo = dateTo;
    result.displayFrom = formatDisplayDate(dateFrom);
    result.displayTo = formatDisplayDate(dateTo);
  }

} else if (cmd === '!delast') {
  let n = parseInt(parts[1] ?? '1', 10);
  if (isNaN(n) || n < 1) {
    result.valid = false;
    result.error = '❌ Invalid number. Usage: !delast N (e.g. !delast 3)';
  } else if (n > 5) {
    result.valid = false;
    result.error = '❌ Maximum allowed is 5. Usage: !delast N (e.g. !delast 5)';
  } else {
    result.action = 'delast';
    result.n = n;
  }

} else {
  result.action = 'unknown';
}

return [{ json: result }];

const discordUser = $('Parse Command').first().json.discordUser.toLowerCase();
const rows = $input.first().json.rows ?? [];

// Find all row indices for this user (1-based, +1 for header row)
const userRows = [];
rows.forEach((r, i) => {
  if ((r.discord_user ?? '').toString().toLowerCase() === discordUser) {
    userRows.push(i + 2); // +1 for 0-index, +1 for header row
  }
});

// Keep the last one, delete all others
const rowsToDelete = userRows.slice(0, -1);

if (rowsToDelete.length === 0) return [{ json: { hasRowsToDelete: false } }];

// Build batchUpdate requests — delete in reverse order to preserve row numbers
const requests = rowsToDelete.reverse().map(rowIndex => ({
  deleteDimension: {
    range: {
      sheetId: 1905451540,
      dimension: 'ROWS',
      startIndex: rowIndex - 1, // 0-based
      endIndex: rowIndex        // exclusive
    }
  }
}));

return [{ json: { hasRowsToDelete: true, requests } }];

const parsed = $('Parse Command').first().json;
const rows = $input.all();
const user = (parsed.discordUser ?? '').toLowerCase();
const dateFrom = parsed.dateFrom;
const dateTo = parsed.dateTo;

const seen = new Map();
for (const row of rows) {
  const r = row.json;
  if ((r.discord_user ?? '').toLowerCase() !== user) continue;
  const rowDate = (r.receipt_date ?? '').slice(0, 10);
  if (!rowDate || rowDate < dateFrom || rowDate > dateTo) continue;
  if (r.is_discount_line === 'TRUE' || r.is_discount_line === true) continue;
  const store = [r.store_name, r.store_branch].filter(Boolean).join(' – ');
  const id = r.receipt_id;
  if (!seen.has(store)) seen.set(store, { total: 0, visits: new Set(), _totals: new Set() });
  const entry = seen.get(store);
  entry.visits.add(id);
  if (!entry._totals.has(id)) {
    entry.total += parseFloat(r.total_amount ?? 0);
    entry._totals.add(id);
  }
}

if (seen.size === 0) return [{ json: { _empty: true } }];

const lines = [...seen.entries()]
  .map(([store, data]) => ({ store, total: data.total, visits: data.visits.size }))
  .sort((a, b) => b.total - a.total)
  .map(s => `  • ${s.store} – £${s.total.toFixed(2)} (${s.visits} visit${s.visits !== 1 ? 's' : ''})`) 
  .join('\n');

return [{ json: { _empty: false, message: `🏪 Stores visited by ${user} (last 52 weeks)\n─────────────────────────────\n${lines}` } }];

const parsed = $('Parse Command').first().json;
const rows = $input.all();
const user = (parsed.discordUser ?? '').toLowerCase();
const n = parsed.n;
const seen = new Map();
for (const row of rows) {
  const r = row.json;
  if ((r.discord_user ?? '').toLowerCase() !== user) continue;
  if (!r.receipt_id || !r.receipt_date) continue;
  if (!seen.has(r.receipt_id)) seen.set(r.receipt_id, { date: (r.receipt_date ?? '').slice(0, 10), store: [r.store_name, r.store_branch].filter(Boolean).join(' – '), total: parseFloat(r.total_amount ?? 0) });
}
if (seen.size === 0) return [{ json: { _empty: true } }];
const sorted = [...seen.values()].sort((a, b) => b.date.localeCompare(a.date)).slice(0, n);
const lines = sorted.map(r => `  ${r.date}  ${r.store} – £${r.total.toFixed(2)}`).join('\n');
return [{ json: { _empty: false, message: `🧾 Last ${sorted.length} receipt${sorted.length !== 1 ? 's' : ''} for ${parsed.discordUser}\n─────────────────────────────\n${lines}` } }];

const discordUser = $('Parse Command').first().json.discordUser.toLowerCase();
const rows = $input.all().filter(r => (r.json.discord_user ?? '').toString().toLowerCase() === discordUser);
const match = rows.length > 0 ? rows[rows.length - 1] : null;
return [{ json: { email: match ? (match.json.email ?? '') : '' } }];

const parsed = $('Parse Command').first().json;
const rows = $('Read Sheets (last)').all();
const user = (parsed.discordUser ?? '').toLowerCase();
const n = parsed.n ?? 1;
const email = $input.first().json.email;

// Filter to this user's rows
const userRows = rows.filter(r => (r.json.discord_user ?? '').toLowerCase() === user);

// Group by receipt_id, keep latest created_at per receipt
const receiptMap = new Map();
for (const row of userRows) {
  const r = row.json;
  const id = r.receipt_id;
  if (!receiptMap.has(id)) {
    receiptMap.set(id, { createdAt: r.created_at ?? '', rows: [] });
  }
  receiptMap.get(id).rows.push(r);
  if ((r.created_at ?? '') > receiptMap.get(id).createdAt) {
    receiptMap.get(id).createdAt = r.created_at ?? '';
  }
}

// Sort by created_at desc, take N
const sortedIds = [...receiptMap.entries()]
  .sort((a, b) => b[1].createdAt.localeCompare(a[1].createdAt))
  .slice(0, n)
  .map(([id]) => id);

const selectedIdSet = new Set(sortedIds);
const filtered = userRows
  .map(r => r.json)
  .filter(r => selectedIdSet.has(r.receipt_id));

if (filtered.length === 0) return [{ json: { _empty: true, email } }];

const headers = ['receipt_id','receipt_date','receipt_time','store_name','store_branch','line_number','product_name','normalised_name','category','quantity','unit_price','line_total','is_discount_line','discount_amount','is_taxable','tax_rate_percent','receipt_total','payment_method'];

filtered.forEach(r => { r.receipt_total = r.total_amount; });

const csvRows = [headers.join(',')];
for (const r of filtered) {
  const row = headers.map(h => {
    const v = r[h] ?? '';
    const s = String(v);
    return s.includes(',') || s.includes('"') || s.includes('\n') ? `"${s.replace(/"/g, '""')}"` : s;
  });
  csvRows.push(row.join(','));
}

const csv = csvRows.join('\n');
const csv_base64 = Buffer.from(csv).toString('base64');
const receiptCount = sortedIds.length;
const totalSpend = [...receiptMap.entries()]
  .filter(([id]) => selectedIdSet.has(id))
  .reduce((sum, [, v]) => sum + parseFloat(v.rows[0].total_amount ?? 0), 0)
  .toFixed(2);

const today = new Date().toISOString().slice(0, 10).replace(/-/g, '');
const filename = `receipts_last${n}_${today}.csv`;

return [{ json: { _empty: false, email, csv_base64, filename, receiptCount, totalSpend, discordUser: parsed.discordUser } }];

const data = $input.first().json;
return [{
  json: {
    email: data.email,
    receiptCount: data.receiptCount,
    totalSpend: data.totalSpend,
    filename: data.filename,
    discordUser: data.discordUser
  },
  binary: {
    attachment: {
      data: data.csv_base64,
      mimeType: 'text/csv',
      fileName: data.filename
    }
  }
}];

const parsed = $('Parse Command').first().json;
const rows = $input.all();
const user = (parsed.discordUser ?? '').toLowerCase();
const dateFrom = parsed.dateFrom;
const dateTo = parsed.dateTo;

let receiptIds = new Set();
let itemCount = 0;
let totalSpend = 0;
const storeMap = new Map();

for (const row of rows) {
  const r = row.json;
  if ((r.discord_user ?? '').toLowerCase() !== user) continue;
  const rowDate = (r.receipt_date ?? '').slice(0, 10);
  if (!rowDate || rowDate < dateFrom || rowDate > dateTo) continue;
  const isDiscount = r.is_discount_line === 'TRUE' || r.is_discount_line === true;
  const store = [r.store_name, r.store_branch].filter(Boolean).join(' – ');
  const id = r.receipt_id;
  if (!receiptIds.has(id)) {
    receiptIds.add(id);
    totalSpend += parseFloat(r.total_amount ?? 0);
    if (!storeMap.has(store)) storeMap.set(store, { spend: 0, visits: 0, _ids: new Set() });
    const s = storeMap.get(store);
    if (!s._ids.has(id)) { s.spend += parseFloat(r.total_amount ?? 0); s.visits += 1; s._ids.add(id); }
  }
  if (!isDiscount) itemCount++;
}

if (receiptIds.size === 0) return [{ json: { _empty: true, displayFrom: parsed.displayFrom, displayTo: parsed.displayTo, discordUser: parsed.discordUser } }];

const topStores = [...storeMap.entries()]
  .sort((a, b) => b[1].spend - a[1].spend)
  .map(([store, data]) => `  • ${store} – £${data.spend.toFixed(2)} (${data.visits} visit${data.visits !== 1 ? 's' : ''})`)  
  .join('\n');

const msg = `📊 Receipt Summary for ${parsed.discordUser}\nPeriod: ${parsed.displayFrom} – ${parsed.displayTo}\n─────────────────────────────\nReceipts:     ${receiptIds.size}\nItems bought: ${itemCount}\nTotal spent:  £${totalSpend.toFixed(2)}\n─────────────────────────────\nStores:\n${topStores}`;
return [{ json: { _empty: false, message: msg } }];

const discordUser = $('Parse Command').first().json.discordUser.toLowerCase();
const rows = $input.all().filter(r => (r.json.discord_user ?? '').toString().toLowerCase() === discordUser);
const match = rows.length > 0 ? rows[rows.length - 1] : null;
return [{ json: { email: match ? (match.json.email ?? '') : '' } }];

const parsed = $('Parse Command').first().json;
const emailRow = $('Find Email (export)').first().json;
const rows = $input.all();
const user = (parsed.discordUser ?? '').toLowerCase();
const dateFrom = parsed.dateFrom;
const dateTo = parsed.dateTo;
const email = emailRow.email;

const filtered = rows.map(r => r.json).filter(r => {
  const rowUser = (r.discord_user ?? '').toLowerCase();
  const rowDate = (r.receipt_date ?? '').slice(0, 10);
  return rowUser === user && rowDate >= dateFrom && rowDate <= dateTo;
});
if (filtered.length === 0) return [{ json: { _empty: true, email, displayFrom: parsed.displayFrom, displayTo: parsed.displayTo } }];

const headers = ['receipt_id','receipt_date','receipt_time','store_name','store_branch','line_number','product_name','normalised_name','category','quantity','unit_price','line_total','is_discount_line','discount_amount','is_taxable','tax_rate_percent','receipt_total','payment_method'];
filtered.forEach(r => { r.receipt_total = r.total_amount; });
const escape = v => { if (v === null || v === undefined) return ''; const s = String(v); return s.includes(',') || s.includes('"') || s.includes('\n') ? `"${s.replace(/"/g, '""')}"` : s; };
const csv = [headers.join(','), ...filtered.map(r => headers.map(h => escape(r[h])).join(','))].join('\n');
const base64 = Buffer.from(csv).toString('base64');

const receiptIds = new Set(filtered.map(r => r.receipt_id));
const totalSpend = [...receiptIds].reduce((sum, id) => { const row = filtered.find(r => r.receipt_id === id); return sum + parseFloat(row?.total_amount ?? 0); }, 0);

return [{ json: { _empty: false, email, csv_base64: base64, filename: `receipts_${dateFrom}_${dateTo}.csv`, displayFrom: parsed.displayFrom, displayTo: parsed.displayTo, receiptCount: receiptIds.size, totalSpend: totalSpend.toFixed(2) } }];

const data = $input.first().json;
const csvBuffer = Buffer.from(data.csv_base64, 'base64');
return [{
  json: {
    email: data.email,
    displayFrom: data.displayFrom,
    displayTo: data.displayTo,
    receiptCount: data.receiptCount,
    totalSpend: data.totalSpend,
    filename: data.filename
  },
  binary: {
    attachment: {
      data: data.csv_base64,
      mimeType: 'text/csv',
      fileName: data.filename
    }
  }
}];

