const parsed = $('Parse Command').first().json;
const user = (parsed.discordUser ?? '').toLowerCase();
const n = parsed.n ?? 1;

const apiResponse = $input.first().json;
const allValues = apiResponse.values ?? [];
const headers = allValues[0] ?? [];
const dataRows = allValues.slice(1);

// Map to objects with row index (1-based sheet row = dataRow index + 2)
const existingRows = dataRows.map((row, i) => {
  const obj = {};
  headers.forEach((h, j) => { obj[h] = row[j] ?? ''; });
  obj._rowIndex = i + 2;
  return obj;
});

// Filter to this user only
const userRows = existingRows.filter(r => (r.discord_user ?? '').toLowerCase() === user);

if (userRows.length === 0) return [{ json: { hasRowsToDelete: false, n } }];

// Group by receipt_id, track max created_at and all sheet row indices per receipt
const receiptMap = new Map();
for (const r of userRows) {
  const id = r.receipt_id;
  if (!receiptMap.has(id)) receiptMap.set(id, { createdAt: r.created_at ?? '', rowIndices: [] });
  const entry = receiptMap.get(id);
  entry.rowIndices.push(r._rowIndex);
  if ((r.created_at ?? '') > entry.createdAt) entry.createdAt = r.created_at ?? '';
}

// Sort by created_at desc, take last N receipts
const sortedReceipts = [...receiptMap.entries()]
  .sort((a, b) => b[1].createdAt.localeCompare(a[1].createdAt))
  .slice(0, n);

if (sortedReceipts.length === 0) return [{ json: { hasRowsToDelete: false, n } }];

// Collect all row indices to delete, sort descending to preserve row numbers during deletion
const allRowIndices = sortedReceipts.flatMap(([, v]) => v.rowIndices).sort((a, b) => b - a);

const requests = allRowIndices.map(rowIndex => ({
  deleteDimension: {
    range: {
      sheetId: 0,
      dimension: 'ROWS',
      startIndex: rowIndex - 1,
      endIndex: rowIndex
    }
  }
}));

const receiptCount = sortedReceipts.length;
return [{ json: { hasRowsToDelete: true, requests, receiptCount, n } }];

parameters.jsonBody:
={
  "system_instruction": {
    "parts": [
      {
        "text": "You are a UK supermarket receipt parser. You will be given a photo of a supermarket receipt. Extract all data and return ONLY valid JSON — no markdown, no explanation, no code fences.

IDENTIFY THE STORE from the header (Aldi, Tesco, Sainsbury's, Asda, Morrisons, Lidl, Waitrose, M&S, Co-op, Costco, etc.).

Store-specific rules:
- Aldi/Lidl: ignore 6-digit PLU codes before item names. A discount line immediately follows the item it applies to — treat it as is_discount_line=true and link discount_amount to the previous item.
- Tesco: The receipt prints the full shelf price on the item line. 'Cc £X.XX' on the next line is the Clubcard price — ignore it for unit_price. The negative amount printed after (e.g. -£1.65) is the Clubcard discount — add a separate discount line with is_discount_line=true, product_name='Clubcard Saving', discount_amount=positive value (e.g. 1.65), line_total=negative value (e.g. -1.65), unit_price=null. 'Special Offer' lines follow the same pattern. 'Reduced To Clear' lines: set unit_price to the reduced price shown, is_discount_line=false. Tesco does NOT print VAT indicators per item — always set is_taxable=false and tax_rate_percent=0 for all Tesco items. If the Savings/Promotions section at the bottom shows a 'Coupons/Vouchers' line (e.g. -£5.00), add one discount line item at the end with product_name='Coupons/Vouchers', is_discount_line=true, discount_amount=positive value, line_total=negative value, unit_price=null, category='Discount'.
- Sainsbury's: ignore Nectar points lines.
- M&S: does NOT print VAT indicators per item — always set is_taxable=false and tax_rate_percent=0 for all M&S items.
- Costco: items have a SKU number on the left (e.g. 2631, 464916). VAT code is the letter printed after the price — A=20% VAT (is_taxable=true, tax_rate_percent=20), Z=0% VAT (is_taxable=false, tax_rate_percent=0). Always use the VAT code from the receipt, do not infer VAT from the product category. If a price has a trailing minus (e.g. '1.00-Z'), output unit_price as -1.00 (negative) and set is_discount_line=true.
- All stores: prices are in the right column; item names in the left column.

General rules:
- Output pure numbers for all prices (2.49 not £2.49).
- quantity defaults to 1 if not shown.
- If a value is not clearly visible, use null — never guess.
- Discount lines: is_discount_line=true, discount_amount=positive number (amount saved).
- Date format: YYYY-MM-DD. Time format: HH:MM (24h).
- VAT: fresh produce/most food = 0%, hot food/snacks/alcohol = 20%.
- Ignore: loyalty ads, barcodes, survey codes, card **** numbers, thank-you lines, cashier names."
      }
    ]
  },
  "contents": [
    {
      "role": "user",
      "parts": [
        {
          "inline_data": {
            "mime_type": "{{ $('Webhook').item.json.body.attachments[0].content_type }}",
            "data": "{{ $json.data }}"
          }
        },
        {
          "text": "Parse this supermarket receipt and return JSON in this exact structure:
{
  "store_name": string,
  "store_branch": string | null,
  "store_address": string | null,
  "store_postcode": string | null,
  "receipt_date": string | null,
  "receipt_time": string | null,
  "currency": "GBP",
  "subtotal": number | null,
  "discount_total": number | null,
  "tax_amount": number | null,
  "total_amount": number | null,
  "payment_method": string | null,
  "last4_card_digits": string | null,
  "loyalty_programme": string | null,
  "items": [
    {
      "line_number": number,
      "product_name": string,
      "normalised_name": string,
      "category": string,
      "quantity": number,
      "unit": string | null,
      "unit_price": number | null,
      "line_total": number | null,
      "is_discount_line": boolean,
      "discount_amount": number | null,
      "is_taxable": boolean,
      "tax_rate_percent": number,
      "brand": string | null,
      "sku_or_barcode": string | null
    }
  ]
}"
        }
      ]
    }
  ],
  "generationConfig": {
    "temperature": 0.1,
    "responseMimeType": "application/json",
    "maxOutputTokens": 8192
  }
}

parameters.jsCode:
const raw = $json.candidates[0].content.parts[0].text;
const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
let parsed;
try { parsed = JSON.parse(cleaned); } catch (e) { return [{ json: { _not_a_receipt: true } }]; }
if (!parsed.items || !Array.isArray(parsed.items) || parsed.items.length === 0) return [{ json: { _not_a_receipt: true } }];

const executionId = $execution.id;
const receiptMeta = {
  receipt_id: executionId,
  store_name: parsed.store_name ?? null,
  store_branch: parsed.store_branch ?? null,
  store_address: parsed.store_address ?? null,
  store_postcode: parsed.store_postcode ?? null,
  receipt_date: parsed.receipt_date ?? null,
  receipt_time: parsed.receipt_time ?? null,
  currency: parsed.currency ?? 'GBP',
  subtotal: parsed.subtotal ?? null,
  discount_total: parsed.discount_total ?? null,
  tax_amount: parsed.tax_amount ?? null,
  total_amount: parsed.total_amount ?? null,
  payment_method: parsed.payment_method ?? null,
  last4_card_digits: parsed.last4_card_digits ?? null,
  loyalty_programme: parsed.loyalty_programme ?? null,
  source_image_url: $('Webhook').item.json.body.attachments[0].url,
  discord_user: $('Webhook').item.json.body.author.username,
