const content = $json.body.content.trim();
const discordUser = $json.body.author.username;
const parts = content.split(/\s+/);
const cmd = parts[0].toLowerCase();

const now = new Date();
const fourWeeksAgo = new Date(now);
fourWeeksAgo.setDate(now.getDate() - 28);
const defaultDateFrom = fourWeeksAgo.toISOString().slice(0, 10);
const defaultDateTo = now.toISOString().slice(0, 10);

const fiftyTwoWeeksAgo = new Date(now);
fiftyTwoWeeksAgo.setDate(now.getDate() - 364);
const storesDateFrom = fiftyTwoWeeksAgo.toISOString().slice(0, 10);

function parseYYYYMMDD(s) {
  if (!s || !/^\d{8}$/.test(s)) return null;
  return `${s.slice(0,4)}-${s.slice(4,6)}-${s.slice(6,8)}`;
}

function formatDisplayDate(isoDate) {
  if (!isoDate) return '';
  const d = new Date(isoDate);
  return d.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
}

let result = { cmd, discordUser, valid: true, error: null };

if (cmd === '!help') {
  result.action = 'help';

} else if (cmd === '!email') {
  const email = parts[1] ?? null;
  if (!email || !/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) {
    result.valid = false;
    result.error = '❌ Invalid email address. Usage: !email you@example.com';
  } else {
    result.action = 'email';
    result.email = email;
  }

} else if (cmd === '!stores') {
  result.action = 'stores';
  result.dateFrom = storesDateFrom;
  result.dateTo = defaultDateTo;

} else if (cmd === '!last') {
  let n = parseInt(parts[1] ?? '1', 10);
  if (isNaN(n) || n < 1) {
    result.valid = false;
    result.error = '❌ Invalid number. Usage: !last N (e.g. !last 5)';
  } else if (n > 20) {
    result.valid = false;
    result.error = '❌ Maximum allowed is 20. Usage: !last N (e.g. !last 20)';
  } else {
    result.action = 'last';
    result.n = n;
  }

} else if (cmd === '!summary') {
  let dateFrom, dateTo;
  if (parts.length >= 3) {
    dateFrom = parseYYYYMMDD(parts[1]);
    dateTo = parseYYYYMMDD(parts[2]);
    if (!dateFrom || !dateTo) {
      result.valid = false;
      result.error = '❌ Invalid date format. Usage: !summary YYYYMMDD YYYYMMDD\nExample: !summary 20260501 20260524';
    } else if (dateFrom > dateTo) {
      result.valid = false;
      result.error = '❌ Start date must be before end date.';
    }
  } else {
    dateFrom = defaultDateFrom;
    dateTo = defaultDateTo;
  }
  if (result.valid) {
    result.action = 'summary';
    result.dateFrom = dateFrom;
    result.dateTo = dateTo;
    result.displayFrom = formatDisplayDate(dateFrom);
    result.displayTo = formatDisplayDate(dateTo);
  }

} else if (cmd === '!export') {
  let dateFrom, dateTo;
  if (parts.length >= 3) {
    dateFrom = parseYYYYMMDD(parts[1]);
    dateTo = parseYYYYMMDD(parts[2]);
    if (!dateFrom || !dateTo) {
      result.valid = false;
      result.error = '❌ Invalid date format. Usage: !export YYYYMMDD YYYYMMDD\nExample: !export 20260501 20260524';
    } else if (dateFrom > dateTo) {
      result.valid = false;
      result.error = '❌ Start date must be before end date.';
    }
  } else {
    dateFrom = defaultDateFrom;
    dateTo = defaultDateTo;
  }
  if (result.valid) {
    result.action = 'export';
    result.dateFrom = dateFrom;
    result.dateTo = dateTo;
    result.displayFrom = formatDisplayDate(dateFrom);
    result.displayTo = formatDisplayDate(dateTo);
  }

} else if (cmd === '!delast') {
  let n = parseInt(parts[1] ?? '1', 10);
  if (isNaN(n) || n < 1) {
    result.valid = false;
    result.error = '❌ Invalid number. Usage: !delast N (e.g. !delast 3)';
  } else if (n > 5) {
    result.valid = false;
    result.error = '❌ Maximum allowed is 5. Usage: !delast N (e.g. !delast 5)';
  } else {
    result.action = 'delast';
    result.n = n;
  }

} else {
  result.action = 'unknown';
}

return [{ json: result }];

