const allValues = apiResponse.values ?? [];
const headers = allValues[0] ?? [];
const dataRows = allValues.slice(1);

// Map to objects with row index (1-based sheet row = dataRow index + 2)
const existingRows = dataRows.map((row, i) => {
  const obj = {};
  headers.forEach((h, j) => { obj[h] = row[j] ?? ''; });
  obj._rowIndex = i + 2;
  return obj;
});

// Filter to this user only
const userRows = existingRows.filter(r => (r.discord_user ?? '').toLowerCase() === user);

if (userRows.length === 0) return [{ json: { hasRowsToDelete: false, n } }];

// Group by receipt_id, track max created_at and all sheet row indices per receipt
const receiptMap = new Map();
for (const r of userRows) {
  const id = r.receipt_id;
  if (!receiptMap.has(id)) receiptMap.set(id, { createdAt: r.created_at ?? '', rowIndices: [] });
  const entry = receiptMap.get(id);
  entry.rowIndices.push(r._rowIndex);
  if ((r.created_at ?? '') > entry.createdAt) entry.createdAt = r.created_at ?? '';
}

// Sort by created_at desc, take last N receipts
const sortedReceipts = [...receiptMap.entries()]
  .sort((a, b) => b[1].createdAt.localeCompare(a[1].createdAt))
  .slice(0, n);

if (sortedReceipts.length === 0) return [{ json: { hasRowsToDelete: false, n } }];

// Collect all row indices to delete, sort descending to preserve row numbers during deletion
const allRowIndices = sortedReceipts.flatMap(([, v]) => v.rowIndices).sort((a, b) => b - a);

const requests = allRowIndices.map(rowIndex => ({
  deleteDimension: {
    range: {
      sheetId: 0,
      dimension: 'ROWS',
      startIndex: rowIndex - 1,
      endIndex: rowIndex
    }
  }
}));

const receiptCount = sortedReceipts.length;
return [{ json: { hasRowsToDelete: true, requests, receiptCount, n } }];

