const raw = $json.candidates[0].content.parts[0].text;
const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();
let parsed;
try { parsed = JSON.parse(cleaned); } catch (e) { return [{ json: { _not_a_receipt: true } }]; }
if (!parsed.items || !Array.isArray(parsed.items) || parsed.items.length === 0) return [{ json: { _not_a_receipt: true } }];

const executionId = $execution.id;
const receiptMeta = {
  receipt_id: executionId,
  store_name: parsed.store_name ?? null,
  store_branch: parsed.store_branch ?? null,
  store_address: parsed.store_address ?? null,
  store_postcode: parsed.store_postcode ?? null,
  receipt_date: parsed.receipt_date ?? null,
  receipt_time: parsed.receipt_time ?? null,
  currency: parsed.currency ?? 'GBP',
  subtotal: parsed.subtotal ?? null,
  discount_total: parsed.discount_total ?? null,
  tax_amount: parsed.tax_amount ?? null,
  total_amount: parsed.total_amount ?? null,
  payment_method: parsed.payment_method ?? null,
  last4_card_digits: parsed.last4_card_digits ?? null,
  loyalty_programme: parsed.loyalty_programme ?? null,
  source_image_url: $('Webhook').item.json.body.attachments[0].url,
  discord_user: $('Webhook').item.json.body.author.username,
  created_at: new Date().toISOString(),
};
return parsed.items.map(item => ({ json: { ...receiptMeta, line_number: item.line_number, product_name: item.product_name, normalised_name: item.normalised_name, category: item.category, quantity: item.quantity, unit: item.unit ?? null, unit_price: item.unit_price ?? null, line_total: item.line_total ?? null, is_discount_line: item.is_discount_line ?? false, discount_amount: item.discount_amount ?? null, is_taxable: item.is_taxable ?? false, tax_rate_percent: item.tax_rate_percent ?? 0, brand: item.brand ?? null, sku_or_barcode: item.sku_or_barcode ?? null } }));

const receipt = $('Filter Empty Rows').first().json;
const receiptDate = (receipt.receipt_date ?? '').toString().trim();
const receiptTime = (receipt.receipt_time ?? '').toString().trim();
const storeName = (receipt.store_name ?? '').toString().trim().toLowerCase();
const storeBranch = (receipt.store_branch ?? '').toString().trim().toLowerCase();
const discordUser = (receipt.discord_user ?? '').toString().trim().toLowerCase();

// Parse rows from Sheets API response
const apiResponse = $('Read Existing Receipts').first().json;
const allValues = apiResponse.values ?? [];
const headers = allValues[0] ?? [];
const dataRows = allValues.slice(1);
const existingRows = dataRows.map(row => {
  const obj = {};
  headers.forEach((h, i) => { obj[h] = row[i] ?? ''; });
  return obj;
});

const duplicate = existingRows.find(r => (
  (r.receipt_date ?? '').toString().trim() === receiptDate &&
  (r.receipt_time ?? '').toString().trim() === receiptTime &&
  (r.store_name ?? '').toString().trim().toLowerCase() === storeName &&
  (r.store_branch ?? '').toString().trim().toLowerCase() === storeBranch &&
  (r.discord_user ?? '').toString().trim().toLowerCase() === discordUser
));

return $('Filter Empty Rows').all().map(item => ({ json: { ...item.json, _is_duplicate: !!duplicate } }));

